"""Sharded (tensor-parallel) PCC test for wan_attention_block — auto-generated by tt_hw_planner.

Runs the SAME component against the SAME captured golden as test_wan_attention_block.py, but on a TP mesh
(MeshShape(1, TP) via the mesh_device fixture). The stub shards its OWN weights (ShardTensorToMesh) and
does its collective internally; this harness replicates the input, runs on the mesh, gathers the
output, and PCC-compares. It imports the single-device test's helpers by path so the reference and
build path are byte-identical — only the device is a mesh. TT_HW_PLANNER_SHARD_TP sets the TP degree.
"""
from __future__ import annotations

import importlib.util
import os
from pathlib import Path

import pytest
import torch

import ttnn
from models.common.utility_functions import comp_pcc

_SIBLING = Path(__file__).resolve().parent / "test_wan_attention_block.py"
_spec = importlib.util.spec_from_file_location("_sd_wan_attention_block", _SIBLING)
_sd = importlib.util.module_from_spec(_spec)
_spec.loader.exec_module(_sd)

_TP = int(os.environ.get("TT_HW_PLANNER_SHARD_TP", "4"))
_DP = int(os.environ.get("TT_HW_PLANNER_SHARD_DP", "1"))
_MESH = (_DP, _TP) if _DP > 1 else _TP


@pytest.mark.parametrize(
    "device_params",
    [{"l1_small_size": 24576, "fabric_config": ttnn.FabricConfig.FABRIC_1D}],
    indirect=True,
)
@pytest.mark.parametrize("mesh_device", [_MESH], indirect=True)
def test_wan_attention_block_sharded(mesh_device):
    torch.manual_seed(int(os.environ.get("TT_PLANNER_TEST_SEED", "0") or "0"))

    torch_module, sample_kwargs, primary = _sd._build_torch_reference()
    try:
        torch_module = torch_module.float()
    except Exception:
        pass
    for _k in list(sample_kwargs.keys()):
        _v = sample_kwargs[_k]
        if isinstance(_v, torch.Tensor) and _v.is_floating_point():
            sample_kwargs[_k] = _v.to(torch.float32)
    _pn, _pt = primary
    if isinstance(_pt, torch.Tensor) and _pt.is_floating_point():
        primary = (_pn, _pt.to(torch.float32))

    with torch.no_grad():
        try:
            torch_out = torch_module(**sample_kwargs)
        except Exception as exc:
            pytest.skip(f"HF reference forward raised {type(exc).__name__}: {exc}")
    torch_out = _sd._normalize_out(torch_out)

    ttnn_module = _sd._build_ttnn_port(mesh_device, torch_module)
    primary_name, primary_tensor = primary
    ttnn_input = _sd._ttnn_from_torch_mesh_safe(primary_tensor, mesh_device)
    extra = {k: v for k, v in sample_kwargs.items() if k != primary_name}
    ttnn_out = ttnn_module(ttnn_input, **extra)
    if isinstance(ttnn_out, tuple) and ttnn_out:
        ttnn_out = ttnn_out[0]
    ttnn_out_torch = _sd._ttnn_to_torch_mesh_safe(ttnn_out, mesh_device).to(torch.float32)

    if isinstance(torch_out, torch.Tensor):
        torch_out = torch_out.to(torch.float32)

    ok, pcc = comp_pcc(torch_out, ttnn_out_torch, _sd.PCC_TARGET)
    print(
        f"[bringup] SHARDED PCC={pcc} target={_sd.PCC_TARGET} tp={_TP} " f"component={_sd.COMPONENT_NAME}",
        flush=True,
    )
    assert ok, f"sharded PCC {pcc} below target {_sd.PCC_TARGET} for {_sd.COMPONENT_NAME} at TP={_TP}"


if __name__ == "__main__":
    import sys

    sys.exit(pytest.main([__file__, "-svv"]))
